use strict;
use warnings;

my %ages = (
    Ali  => 25,
    Veli => 30,
    Ayse => 28,
);

print "Tum kayitlar:\n";
foreach my $name (keys %ages) {
    print "$name -> $ages{$name} yasinda\n";
}

# Anahtar kontrolu
if (exists $ages{Ali}) {
    print "\nAli'nin yasi: $ages{Ali}\n";
}

# Guncelleme
$ages{Ali} = 26;
print "Ali'nin yeni yasi: $ages{Ali}\n";

# Yeni eleman ekleme
$ages{Can} = 22;
print "\nCan eklendi, kayit sayisi: " . scalar(keys %ages) . "\n";

# Silme
delete $ages{Veli};
print "\nVeli silindikten sonra kayit sayisi: " . scalar(keys %ages) . "\n";

# Olmayan anahtar kontrolu
if (!exists $ages{Zeynep}) {
    print "\nZeynep hash'te bulunamadi.\n";
}

# Anahtarlar ve degerler
my @keys = keys %ages;
my @values = values %ages;
print "\nAnahtarlar: @keys\n";
print "Degerler: @values\n";
